<script setup>
import { computed, onMounted, onUnmounted, ref } from 'vue'
import stageSheet from '../assets/landing/traceability-stages.png'
import systemScenes from '../assets/landing/system-scenes.png'

const emit = defineEmits(['enter-admin'])
const pointer = ref({ x: 50, y: 50 })
const activeIndex = ref(null)
const railProgress = ref(0)
const stages = [
  { no: '01', title: '田间采收', text: '产地、品种与原料批次，从第一刻开始留下记录。', position: '0%' },
  { no: '02', title: '加工建批', text: '每一次清洗、分拣与入库，都归入同一批次。', position: '25%' },
  { no: '03', title: '质量检验', text: '报告、留样与批次校验，共同构成可信凭据。', position: '50%' },
  { no: '04', title: '冷链运输', text: '仓储、车辆和温度数据，持续在线归档。', position: '75%' },
  { no: '05', title: '终端验真', text: '扫码即可回看一份食品走过的完整旅程。', position: '100%' },
]
const pointerStyle = computed(() => ({ '--mx': `${pointer.value.x}%`, '--my': `${pointer.value.y}%`, '--splice': railProgress.value.toFixed(3) }))
function move(event) { const rect = event.currentTarget.getBoundingClientRect(); pointer.value = { x: Math.max(0, Math.min(100, ((event.clientX - rect.left) / rect.width) * 100)), y: Math.max(0, Math.min(100, ((event.clientY - rect.top) / rect.height) * 100)) } }
function updateRailProgress() { const rail = document.querySelector('.journey-rail'); if (!rail) return; const rect = rail.getBoundingClientRect(); railProgress.value = Math.max(0, Math.min(1, (window.innerHeight * .82 - rect.top) / (rect.height + window.innerHeight * .3))) }
onMounted(() => { window.addEventListener('scroll', updateRailProgress, { passive: true }); updateRailProgress() })
onUnmounted(() => window.removeEventListener('scroll', updateRailProgress))
</script>

<template>
  <section class="journey-detail" :style="pointerStyle" @pointermove="move">
    <div class="journey-intro"><p>从一颗种子到一次扫码</p><h2>每一次流转，都留下<br><em>可以回看的证据。</em></h2><span>把食品安全从一份承诺，变成每个节点都能被验证的事实。</span></div>
    <div class="journey-rail" aria-label="食品溯源流程"><article v-for="(stage, index) in stages" :key="stage.no" class="journey-card" :class="{ active: activeIndex === index }" @pointerenter="activeIndex = index" @pointerleave="activeIndex = null"><div class="journey-photo" :style="{ backgroundImage: `url(${stageSheet})`, backgroundPosition: `${stage.position} center` }"></div><div class="journey-copy"><b>{{ stage.no }}</b><h3>{{ stage.title }}</h3><p>{{ stage.text }}</p></div></article></div>
    <div class="proof-block"><div class="proof-copy"><p>一条可信链路</p><h2>系统不会替食品说话，<br>它只负责把事实留下。</h2><span>主体资质、生产批次、检测报告、冷链节点和消费者查询，围绕同一个溯源码形成可以校验的证据链。</span></div><div class="proof-mark" aria-hidden="true"><i></i><strong>TRACE<br>PROOF</strong><small>verified<br>by record</small></div></div>
    <section class="system-showcase"><div class="showcase-heading"><p>为每一类参与者准备</p><h2>从生产现场，到<br>消费者手里的那一刻。</h2></div><div class="scene-grid"><article><div class="scene-image scene-origin" :style="{ backgroundImage: `url(${systemScenes})` }"></div><h3>企业建档</h3><p>用主体、资质与批次信息建立食品的第一份可信档案。</p></article><article><div class="scene-image scene-lab" :style="{ backgroundImage: `url(${systemScenes})` }"></div><h3>质检留痕</h3><p>检验报告、留样记录与关键指标，均可关联至产品批次。</p></article><article><div class="scene-image scene-cold" :style="{ backgroundImage: `url(${systemScenes})` }"></div><h3>冷链监控</h3><p>用仓储、运输与温控数据，持续还原真实流转状态。</p></article><article><div class="scene-image scene-home" :style="{ backgroundImage: `url(${systemScenes})` }"></div><h3>公众验真</h3><p>让消费者在需要确认时，看见一份清楚、完整的来处。</p></article></div></section>
    <footer class="journey-footer"><div><strong>食品溯源系统</strong><span>让安全看得见，让每一次选择有据可查。</span></div><div class="footer-links"><a href="#top">全链旅程</a><a href="#system-detail">系统能力</a><button @click="emit('enter-admin')">进入管理后台 <b>→</b></button></div><small>© 2026 Food Traceability System · 软件工程课程设计</small></footer>
  </section>
</template>

